"use strict";(self.webpackChunkmagento2_hyva_jewellery_theme_docs=self.webpackChunkmagento2_hyva_jewellery_theme_docs||[]).push([[2765],{7870(t,e,r){r.r(e),r.d(e,{comp:()=>s,data:()=>i});var o=r(641);const a={},s=(0,r(6262).A)(a,[["render",function(t,e){return(0,o.uX)(),(0,o.CE)("div",null,[...e[0]||(e[0]=[(0,o.Fv)('<h1 id="category-page" tabindex="-1"><a class="header-anchor" href="#category-page"><span>Category Page</span></a></h1><p>The <strong>Category Page</strong> shows products from one category, such as Rings, Earrings, Necklaces, Bracelets, New Arrivals, Best Sellers, or Sale.</p><p>Use this page to help shoppers browse and filter products quickly.</p><h2 id="what-shoppers-see" tabindex="-1"><a class="header-anchor" href="#what-shoppers-see"><span>What shoppers see</span></a></h2><table><thead><tr><th>Area</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Category title</strong></td><td>Shows the current category name.</td></tr><tr><td><strong>Category text</strong></td><td>Short text about the category.</td></tr><tr><td><strong>Product grid</strong></td><td>Shows product image, name, price, rating, stock, and badges.</td></tr><tr><td><strong>Filter button</strong></td><td>Opens filters so shoppers can narrow the products.</td></tr><tr><td><strong>Sort</strong></td><td>Lets shoppers sort products by Position, Product Name, or Price.</td></tr><tr><td><strong>ASC / DESC</strong></td><td>Changes the sort direction.</td></tr><tr><td><strong>Grid columns</strong></td><td>Lets shoppers change the desktop grid between 4 columns and 3 columns.</td></tr><tr><td><strong>Pagination</strong></td><td>Lets shoppers move to the next product page.</td></tr><tr><td><strong>Show per page</strong></td><td>Lets shoppers show 12, 24, or 36 products per page.</td></tr></tbody></table><h2 id="filters" tabindex="-1"><a class="header-anchor" href="#filters"><span>Filters</span></a></h2><p>The theme supports layered filters on category pages. In the demo store, shoppers can filter by:</p><ul><li>Category</li><li>Price</li><li>Jewelry Material</li><li>Metal Color</li><li>Stone</li><li>Diamond Shape</li><li>Occasion</li><li>Gender</li><li>Purity</li><li>Ring Size</li><li>Finish</li><li>Certification</li></ul><p>Each filter option can show the product count, such as <code>Gold (88)</code>.</p><div class="hint-container tip"><p class="hint-container-title">Tips</p><p>If a filter does not show, check the product attribute in Magento Admin. The attribute must be enabled for layered navigation and products must have values for it.</p></div><h2 id="product-card-actions" tabindex="-1"><a class="header-anchor" href="#product-card-actions"><span>Product card actions</span></a></h2><p>Each product card can show these actions:</p><table><thead><tr><th>Action</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Add to Cart</strong></td><td>Adds simple products to cart directly from the listing.</td></tr><tr><td><strong>View Product</strong></td><td>Opens the product page when the product needs options first.</td></tr><tr><td><strong>Wishlist</strong></td><td>Adds the item to the shopper&#39;s wishlist.</td></tr><tr><td><strong>Compare</strong></td><td>Adds the item to product compare.</td></tr><tr><td><strong>Quick View</strong></td><td>Opens a quick product preview without leaving the category page.</td></tr></tbody></table><p>Product cards can also show:</p><ul><li>Sale price</li><li>New badge</li><li>Hot badge</li><li>Rating stars</li><li>Review count</li><li>In Stock, Out of Stock, or low stock message</li><li>Second product image on hover, when another image is available</li></ul><h2 id="how-to-check-a-category-page" tabindex="-1"><a class="header-anchor" href="#how-to-check-a-category-page"><span>How to check a category page</span></a></h2><ol><li>Open a category from the menu.</li><li>Check that the category title and text look correct.</li><li>Open <strong>Filter</strong> and test a few filters.</li><li>Change <strong>Sort</strong> and <strong>ASC / DESC</strong>.</li><li>Switch between 4 columns and 3 columns on desktop.</li><li>Open page 2 from pagination.</li><li>Change <strong>Show per page</strong>.</li><li>Test Wishlist, Compare, Quick View, and Add to Cart.</li><li>Check the same page on mobile.</li></ol><h2 id="good-practice" tabindex="-1"><a class="header-anchor" href="#good-practice"><span>Good practice</span></a></h2><ul><li>Keep category names short and clear.</li><li>Add good product images for every product.</li><li>Add values for important jewellery attributes, such as material, stone, size, and occasion.</li><li>Do not add too many filters if shoppers do not need them.</li><li>Keep the first category page fast by using clean product images.</li></ul>',19)])])}]]),i=JSON.parse('{"path":"/hyva-jewelry-theme/pages/category.html","title":"Category Page","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"What shoppers see","slug":"what-shoppers-see","link":"#what-shoppers-see","children":[]},{"level":2,"title":"Filters","slug":"filters","link":"#filters","children":[]},{"level":2,"title":"Product card actions","slug":"product-card-actions","link":"#product-card-actions","children":[]},{"level":2,"title":"How to check a category page","slug":"how-to-check-a-category-page","link":"#how-to-check-a-category-page","children":[]},{"level":2,"title":"Good practice","slug":"good-practice","link":"#good-practice","children":[]}],"git":{"contributors":[{"name":"anikesh kumar","username":"","email":"anikesh.kumar204@webkul.in","commits":1}],"changelog":[{"hash":"65ee1538c72e98b02c838952f96993746b91fe68","time":1783608557000,"email":"anikesh.kumar204@webkul.in","author":"anikesh kumar","message":"init"}]},"filePathRelative":"pages/category.md"}')}}]);